import 'package:flutter/material.dart';

/// Supported locale definitions with display info
class SupportedLocale {
  final Locale locale;
  final String flag;
  final String displayName; // Name in its own language
  final String region;

  const SupportedLocale({
    required this.locale,
    required this.flag,
    required this.displayName,
    required this.region,
  });

  String get code =>
      locale.languageCode +
      (locale.countryCode != null ? '_${locale.countryCode}' : '');
}

