    locale: Locale('ru', 'RU'),
    flag: '🇷🇺',
    displayName: 'Русский',
    region: 'Россия');

  static const List<SupportedLocale> all = [
    // North America
    enUS, enCA, frCA, esMX,
    // EU
    deDE, deAT, frFR, esES, itIT, ptPT, nlNL, nlBE, frBE, deLU,
    plPL, roRO, csCZ, elGR, huHU, svSE, bgBG, daDK, fiFI,
    skSK, hrHR, ltLT, slSI, lvLV, etEE, enIE, elCY, enMT,
    // Russia
    ruRU,
  ];

  /// Get the list of Flutter Locale objects
  static List<Locale> get supportedLocales => all.map((l) => l.locale).toList();

  /// Find a SupportedLocale by code (e.g. 'de_DE')
  static SupportedLocale? findByCode(String code) {
    try {
      return all.firstWhere((l) => l.code == code);
    } catch (_) {
      return null;
    }
  }
}

/// Simple localization class — translations are stored as maps
